    # q.k = -SCALE * (j - (i-1))**2  using:
    #   Q[i] = [SCALE*1, SCALE*2*(i-1), -SCALE*(i-1)**2]  (3 dims)
    #   K[j] = [-j**2, j, 1]                              (3 dims)
    # Expand (i-1)**2 = i**2 - 2*i + 1.
    SHIFT_SCALE = 100.0
    # Q row 0 = SHIFT_SCALE * pos_const
    attn0.W_q.weight.data[0, POS_CONST_DIM] = SHIFT_SCALE
